package main

import "fmt"

func main() {
    // ---- Standard for loop ----
    fmt.Println("=== Standard for ===")
    for i := 0; i < 5; i++ {
        fmt.Println("i:", i)
    }

    // ---- For as while ----
    fmt.Println("=== For as while ===")
    count := 0
    for count < 5 {
        fmt.Println("count:", count)
        count++
    }

    // ---- Infinite loop ----
    fmt.Println("=== Infinite loop (break) ===")
    i := 0
    for {
        if i >= 3 {
            break
        }
        fmt.Println("i:", i)
        i++
    }

    // ---- For with continue ----
    fmt.Println("=== For with continue ===")
    for i := 0; i < 10; i++ {
        if i%2 == 0 {
            continue  // Skip even numbers
        }
        fmt.Println("Odd:", i)
    }

    // ---- Range over slice ----
    fmt.Println("=== Range over slice ===")
    numbers := []int{10, 20, 30, 40, 50}
    for index, value := range numbers {
        fmt.Println("index:", index, "value:", value)
    }

    // ---- Range over array ----
    fmt.Println("=== Range over array ===")
    arr := [3]string{"Sword", "Shield", "Potion"}
    for i, item := range arr {
        fmt.Println(i, ":", item)
    }

    // ---- Range over map ----
    fmt.Println("=== Range over map ===")
    scores := map[string]int{"Hero": 100, "Aragorn": 85, "Gandalf": 95}
    for name, score := range scores {
        fmt.Println(name, ":", score)
    }

    // ---- Range with only index ----
    fmt.Println("=== Range with only index ===")
    for i := range numbers {
        fmt.Println("Index:", i)
    }

    // ---- Range with only value ----
    fmt.Println("=== Range with only value ===")
    for _, value := range numbers {
        fmt.Println("Value:", value)
    }

    // ---- Loop over string (bytes) ----
    fmt.Println("=== Loop over string ===")
    text := "Hello"
    for i, char := range text {
        fmt.Printf("i: %d, char: %c\n", i, char)
    }
}

