phase3.solution:
package main

import "fmt"

func main() {
    for i := 1; i <= 5; i++ {
        fmt.Println("Forward:", i)
    }

    for count := 5; count > 0; count-- {
        fmt.Println("Backward:", count)
    }

    items := []string{"Sword", "Shield", "Potion"}
    for i, item := range items {
        fmt.Println(i, ":", item)
    }
}
